function ensureDir(p) {
  fs.mkdirSync(p, { recursive: true });
}

function writeFile(filePath, content) {
  fs.writeFileSync(filePath, content, 'utf8');
}

function toYamlArray(items, indent = 0) {
  const space = ' '.repeat(indent);
  return items.map((item) => `${space}- ${item}`).join('\n');
}

function toTitleCase(slug) {
  return slug
    .split('-')
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ');
}

function makeBriefEn(business, bData) {
  const title = toTitleCase(business);
  const apps = bData.apps || [];
  const essential = apps.filter((a) => a.priority === 'essential');
  const important = apps.filter((a) => a.priority === 'important');
  const advanced = apps.filter((a) => a.priority === 'advanced');

  let out = `# Business Brief - ${title}\n\n`;

  // Industry overview
  out += `## Industry Overview\n`;
  if (bData.brief_en && bData.brief_en.length) {
    bData.brief_en.forEach((p) => { out += `${p}\n\n`; });
  } else {
    out += `This business blueprint targets the ${title} domain.\n\n`;
  }

  // Key pain points
  if (bData.key_pain_points && bData.key_pain_points.length) {
    out += `## Key Pain Points\n`;
    bData.key_pain_points.forEach((p) => { out += `- ${p}\n`; });
    out += `\n`;
  }

  // Target personas
  if (bData.target_personas && bData.target_personas.length) {
    out += `## Target Personas\n`;
    bData.target_personas.forEach((p) => { out += `- **${p.role}**: ${p.focus}\n`; });
    out += `\n`;
  }

  // KPIs
  if (bData.kpis && bData.kpis.length) {
    out += `## Key Performance Indicators\n`;
    bData.kpis.forEach((k) => { out += `- ${k}\n`; });
    out += `\n`;
  }

  // Regulatory landscape
  if (bData.regulations && bData.regulations.length) {
    out += `## Regulatory & Compliance Landscape\n`;
    bData.regulations.forEach((r) => { out += `- ${r}\n`; });
    out += `\n`;
  }

  // Digital maturity
  if (bData.digital_maturity) {
    out += `## Typical Digital Maturity\n${bData.digital_maturity}\n\n`;
  }

  // App catalog index by priority
  out += `## App Catalog (${apps.length} apps)\n\n`;
  if (essential.length) {
    out += `### Essential (build first)\n`;
    essential.forEach((a, i) => { out += `${i + 1}. **${a.app}**${a.description ? ' — ' + a.description : ''}\n`; });
    out += `\n`;
  }
  if (important.length) {
    out += `### Important (phase 2)\n`;
    important.forEach((a, i) => { out += `${i + 1}. **${a.app}**${a.description ? ' — ' + a.description : ''}\n`; });
    out += `\n`;
  }
  if (advanced.length) {
    out += `### Advanced (scale & optimization)\n`;
    advanced.forEach((a, i) => { out += `${i + 1}. **${a.app}**${a.description ? ' — ' + a.description : ''}\n`; });
    out += `\n`;
  }

  out += `## Notes\n- Prompts can be written in Vietnamese.\n- Generated technical files should stay in English or bilingual EN/VI.\n`;
  return out;
}

function makeBriefVi(business, lines) {
  return `# Business Brief - ${business}\n\n## Bối cảnh\n${lines.map((l) => `- ${l}`).join('\n')}\n\n## Ghi chú\n- Prompt có thể viết bằng tiếng Việt.\n- Tài liệu output nên để EN hoặc song ngữ EN/VI.\n`;
}

function makeInitYaml(business, appData) {
  const merged = appData;

  const lines = [
    `business: ${business}`,
    `app: ${merged.app}`,
    `project_name_pattern: "{business}-{app}"`,
    `priority: ${merged.priority}`,
  ];

  if (merged.description) {
    lines.push(`description: "${merged.description}"`);
  }

  lines.push(
    `language_output:`,
    `  - en`,
    `  - vi`,
    `default_language: en`,
    `theme_options:`,
    `  - corporate`,
    `  - modern`,
    `  - minimal`,
    `default_theme: corporate`,
    `mode_options:`,
    `  - replace_existing`,
    `  - new_app`,
  );

  // Target users
  const users = merged.target_users || ['owner', 'manager', 'staff'];

  lines.push(`target_users:`);
  lines.push(toYamlArray(users, 2));

  // Core modules
  lines.push(`core_modules:`);
  lines.push(toYamlArray(merged.core_modules, 2));

  // Key user flows
  if (merged.key_user_flows && merged.key_user_flows.length) {
    lines.push(`key_user_flows:`);
    lines.push(toYamlArray(merged.key_user_flows, 2));
  }

  // Data entities
  if (merged.data_entities && merged.data_entities.length) {
    lines.push(`data_entities:`);
    lines.push(toYamlArray(merged.data_entities, 2));
  }

  // Integrations
  lines.push(`integrations:`);
  lines.push(toYamlArray(merged.integrations, 2));

  // NFR — use app-specific or fallback
  const nfr = merged.nfr || {};
  lines.push(`nfr:`);
  lines.push(`  performance: "${nfr.performance || 'P95 API < 400ms for core operations'}"`);
  lines.push(`  security: "${nfr.security || 'RBAC, audit log, encrypted sensitive fields'}"`);
  lines.push(`  availability: "${nfr.availability || '99.9% monthly'}"`);
  lines.push(`  ai_governance: "${nfr.ai_governance || 'Human review required for AI-generated business logic'}"`);

  // Compliance
  lines.push(`compliance:`);
  lines.push(toYamlArray(merged.compliance, 2));

  // Tech stack hints
  if (merged.tech_stack_hints && merged.tech_stack_hints.length) {
    lines.push(`tech_stack_hints:`);
    lines.push(toYamlArray(merged.tech_stack_hints, 2));
  }

  return lines.join('\n') + '\n';
}

function main() {
  ensureDir(BUSINESSES_DIR);

  BUSINESS_CATALOG.forEach((b) => {
    const businessDir = path.join(BUSINESSES_DIR, b.business);
    const appsDir = path.join(businessDir, 'apps');
    ensureDir(appsDir);

    writeFile(path.join(businessDir, 'business-brief.en.md'), makeBriefEn(b.business, b));
    writeFile(path.join(businessDir, 'business-brief.vi.md'), makeBriefVi(b.business, b.brief_vi));

    b.apps.forEach((appData) => {
      const appDir = path.join(appsDir, appData.app);
      ensureDir(appDir);
      writeFile(path.join(appDir, 'init.tech.yaml'), makeInitYaml(b.business, appData));
    });

    const appCatalog = [
      `business: ${b.business}`,
      `apps:`,
      ...b.apps.map((a) => `  - app: ${a.app}\n    priority: ${a.priority}`),
      '',
    ].join('\n');

    writeFile(path.join(businessDir, 'app-catalog.yaml'), appCatalog);
  });

  const summary = {
    businesses: BUSINESS_CATALOG.length,
    apps: BUSINESS_CATALOG.reduce((sum, b) => sum + b.apps.length, 0),
  };

  writeFile(
    path.join(ROOT, 'BUSINESS_APP_MATRIX.md'),
    [
      '# Business App Matrix',
      '',
      `Generated businesses: ${summary.businesses}`,
      `Generated app blueprints: ${summary.apps}`,
      '',
      'Priority levels:',
      '- essential: should be implemented first',
      '- important: phase 2 after core operations are stable',
      '- advanced: scale/optimization layer',
      '',
      'This matrix is generated from `generators/seed-business-catalog.js`.',
    ].join('\n') + '\n'
  );

  console.log(`Seeded ${summary.businesses} businesses and ${summary.apps} app blueprints.`);
}

main();
